@@ -100,6 +100,22 @@ export class InputRouter {
         metaWindow.move_frame(true, newX, newY);
         metaWindow.activate(global.get_current_time());

+        // Expand the container to cover the same area as the real window
+        // so the mouse stays "inside" it. Otherwise leave-event fires
+        // immediately because the small stamp container no longer has
+        // the cursor over it.
+        this._origContainerPos = {x: container.x, y: container.y};
+        this._origContainerSize = {w: container.width, h: container.height};
+        container.set_position(newX, newY);
+        container.set_size(frameRect.width, frameRect.height);
+
+        // Also resize the clone inside so it fills the expanded container
+        const clone = container.get_first_child();
+        if (clone) {
+            this._origCloneSize = {w: clone.width, h: clone.height};
+            clone.set_size(frameRect.width, frameRect.height);
+        }
+
         // Make clone transparent but keep reactive for leave-event
         container.opacity = 0;
     }
@@ -118,12 +134,28 @@ export class InputRouter {
         if (this._wasMinimized && !metaWindow.minimized)
             metaWindow.minimize();

-        if (this._hoverContainer)
+        if (this._hoverContainer) {
             this._hoverContainer.opacity = 255;
+            // Restore container to original stamp size/position
+            if (this._origContainerPos) {
+                this._hoverContainer.set_position(
+                    this._origContainerPos.x, this._origContainerPos.y);
+            }
+            if (this._origContainerSize) {
+                this._hoverContainer.set_size(
+                    this._origContainerSize.w, this._origContainerSize.h);
+                const clone = this._hoverContainer.get_first_child();
+                if (clone && this._origCloneSize)
+                    clone.set_size(this._origCloneSize.w, this._origCloneSize.h);
+            }
+        }

         this._hoverWindow = null;
         this._hoverContainer = null;
         this._wasMinimized = false;
+        this._origContainerPos = null;
+        this._origContainerSize = null;
+        this._origCloneSize = null;
     }

